/* eslint-disable no-console */
const { parseGrep, shouldTestRun } = require('@cypress/grep/src/utils');
const globby = require('globby');
const fs = require('fs');
const { getTestNames } = require('find-test-names');

// file with tests execution times, generated by time-balancer.js script. Has format { "C1234": 120000, "C5678": 300000, ... }
const TESTS_EXECUTION_TIME_FILE = './doc/testsExecutionTime.json';

function splitTestsOnChunks(numberOfThreads, grepTags, envVars = '', printSpecs = false) {
  console.log(`Number of threads: ${numberOfThreads}`);
  console.log(`Environment variables: ${envVars}`);
  console.log(`Grep tags: \n${grepTags}\n`);
  const parsedGrep = parseGrep(null, grepTags);

  const specFiles = globby.sync('cypress/e2e/**/*.cy.js');
  const testSpecs = [];
  const chunks = Array.from({ length: numberOfThreads }, (_) => ({ totalDuration: 0, testIds: [] }));
  const chunksWithSpecFiles = Array.from({ length: numberOfThreads }, (_) => ({ totalDuration: 0, testSpecFiles: [] }));
  specFiles.forEach((specFile) => {
    const testsInSpecFile = [];
    const text = fs.readFileSync(specFile, { encoding: 'utf8' });
    let testInfo;
    try {
      testInfo = getTestNames(text);
    } catch (err) {
      console.error('Could not determine test names in file: %s', specFile);
      testInfo = { tests: [] };
    }
    testInfo.tests.forEach((test) => {
      const shouldRun = shouldTestRun(parsedGrep, null, test.tags);
      if (shouldRun) {
        const filteredTags = test.tags.filter((tag) => tag.startsWith('C') || tag.startsWith('TC'));
        if (filteredTags.includes(undefined)) {
          console.log(`Test without ID found in file ${specFile} - ${test.tags}`);
        }
        testsInSpecFile.push(filteredTags[0]);
      }
    });
    if (testsInSpecFile.length > 0) {
      testSpecs.push({ ids: Array.from(new Set(testsInSpecFile)), spec: specFile });
    }
  });

  if (testSpecs.length === 0) {
    throw new Error('No tests found with provided tags.');
  }

  let testsExecutionTimes = {};
  try {
    const testsExecutionTimeContent = fs.readFileSync(TESTS_EXECUTION_TIME_FILE, {
      encoding: 'utf8',
    });
    testsExecutionTimes = JSON.parse(testsExecutionTimeContent);
  } catch (err) {
    console.error(`Error reading ${TESTS_EXECUTION_TIME_FILE} file.`, err);
  }


  function getTestDuration(testId) {
    if (testId in testsExecutionTimes) {
      return testsExecutionTimes[testId];
    } else {
      return 2 * 60 * 1000; // fallback duration for unknown test (2 minutes)
    }
  }

  function getTestDurationForSpec(testSpecIds) {
    let duration = 0;
    testSpecIds.forEach((testId) => {
      duration += getTestDuration(testId);
    });
    return duration;
  }

  for (const testSpec of testSpecs) {
    chunks.sort((a, b) => a.totalDuration - b.totalDuration);
    chunks[0].testIds.push(...testSpec.ids);
    chunks[0].totalDuration += getTestDurationForSpec(testSpec.ids);

    chunksWithSpecFiles.sort((a, b) => a.totalDuration - b.totalDuration);
    chunksWithSpecFiles[0].testSpecFiles.push(testSpec.spec);
    chunksWithSpecFiles[0].totalDuration += getTestDurationForSpec(testSpec.ids);
  }

  const fileJson = {};
  fileJson.workers = [];
  fileJson.specs = [];

  console.log(`\nTotal number of tests: ${testSpecs.reduce((acc, val) => acc + val.ids.length, 0)}\n`);

  console.log(`Number of chunks: ${chunks.length}\n`);
  chunks.forEach((chunk, index) => {
    const parsedChunk = `--env ${envVars !== '' ? envVars + ',' : ''}grepTags='${chunk.testIds.join(' ')}'`;
    fileJson.workers.push(parsedChunk);
    console.log(
      `Chunk #${index + 1}: ${chunk.testIds.length}, Estimated duration: ${new Date(chunk.totalDuration).toISOString().slice(11, 19)}`,
    );
    console.log(parsedChunk + '\n');
  });

  chunksWithSpecFiles.forEach((chunk, index) => {
    const parsedChunk = `${envVars !== '' ? `--env ${envVars} ` : ''}--spec='${chunk.testSpecFiles.join(',')}'`;
    fileJson.specs.push(parsedChunk);
    if (printSpecs) {
      console.log(
        `Chunk #${index + 1}: ${chunk.testSpecFiles.length}, Estimated duration: ${new Date(chunk.totalDuration).toISOString().slice(11, 19)}`,
      );
      console.log(parsedChunk + '\n');
    }
  });

  fs.writeFile('parallelWorkers.json', JSON.stringify(fileJson), 'utf8', (err) => {
    if (err) {
      console.error('Error writing file', err);
    } else {
      console.log('File has been written');
    }
  });
}

module.exports = {
  splitTestsOnChunks,
};
